/**
 * API type aliases — bridges auto-generated OpenAPI types to clean domain names.
 *
 * The raw types live in src/generated/api.ts (auto-generated by openapi-typescript).
 * This file maps them to UI-friendly names so the rest of the codebase doesn't
 * couple to the generated schema naming convention (e.g., TaskRunResponse → TaskRun).
 *
 * UI-only types (filters, query params, visualization) remain in their respective
 * domain files within src/types/.
 */

import type { components } from '../generated/api';

type Schemas = components['schemas'];

