// Managed resource run (returned by GET /managed/{key}/runs)
export type ManagedRun = {
  task_run_id: string;
  status: string;
  run_context?: Record<string, unknown> | null;
  started_at?: string | null;
  completed_at?: string | null;
  created_at: string;
};

// Managed schedule (returned by GET/PUT /managed/{key}/schedule)
export type ManagedSchedule = {
  schedule_id: string;
  schedule_type: string;
  schedule_value: string;
  enabled: boolean;
  timezone: string;
  next_run_at?: string | null;
  last_run_at?: string | null;
};

